def is_duplicate(self, user_id: str, content: str) -> bool:
    key = f'{user_id}:{content}'
    now = time.time()
    if key in self._recent:
        last_time = self._recent[key]
        if now - last_time <= self.window:
            return True
    self._recent[key] = now
    return False
